/* ── Sigmoid: int32_t Q20 → uint16_t Q15 ──────────────────────── */
uint16_t sigmoid_q20_to_q15(int32_t x_q20)
{
    /* Boundary saturation */
    if (x_q20 >= SIGMOID_LUT_X_MAX_Q20) return 32768;   /* 1.0 in Q15 */
    if (x_q20 <= SIGMOID_LUT_X_MIN_Q20) return 0;
    /* Map to LUT index: x ∈ [-8,8] Q20 → idx ∈ [0, 4095] */
    int64_t mapped = (int64_t)(x_q20 - SIGMOID_LUT_X_MIN_Q20) * 4095;
    int32_t idx = (int32_t)(mapped / (SIGMOID_LUT_X_MAX_Q20 - SIGMOID_LUT_X_MIN_Q20));
    if (idx >= 4095) return sigmoid_lut_q15[4095];
    /* Linear interpolation */
    uint32_t frac = (uint32_t)(mapped % (SIGMOID_LUT_X_MAX_Q20 - SIGMOID_LUT_X_MIN_Q20));
    uint32_t denom = (uint32_t)(SIGMOID_LUT_X_MAX_Q20 - SIGMOID_LUT_X_MIN_Q20);
    uint32_t y0 = sigmoid_lut_q15[idx];
    uint32_t y1 = sigmoid_lut_q15[idx + 1];
    return (uint16_t)(y0 + ((y1 - y0) * frac) / denom);
}

/* ── Tanh: int32_t Q20 → int16_t Q15 ─────────────────────────── */
int16_t tanh_q20_to_q15(int32_t x_q20)
{
    if (x_q20 >= TANH_LUT_X_MAX_Q20) return  32767;   /* 1.0 in Q15 */
    if (x_q20 <= TANH_LUT_X_MIN_Q20) return -32768;
    int64_t mapped = (int64_t)(x_q20 - TANH_LUT_X_MIN_Q20) * 4095;
    int32_t idx = (int32_t)(mapped / (TANH_LUT_X_MAX_Q20 - TANH_LUT_X_MIN_Q20));
    if (idx >= 4095) return tanh_lut_q15[4095];
    uint32_t frac = (uint32_t)(mapped % (TANH_LUT_X_MAX_Q20 - TANH_LUT_X_MIN_Q20));
    uint32_t denom = (uint32_t)(TANH_LUT_X_MAX_Q20 - TANH_LUT_X_MIN_Q20);
    int32_t y0 = tanh_lut_q15[idx];
    int32_t y1 = tanh_lut_q15[idx + 1];
    return (int16_t)(y0 + ((y1 - y0) * (int32_t)frac) / (int32_t)denom);
}

/* ── Log10: int32_t Q20 → int32_t Q20 ────────────────────────── */
int32_t log10_q20_to_q20(int32_t x_q20)
{
    if (x_q20 <= 0) return log10_lut_q20[0];
    if (x_q20 >= LOG10_LUT_X_MAX_Q20) return log10_lut_q20[511];
    int64_t mapped = (int64_t)(x_q20 - LOG10_LUT_X_MIN_Q20) * 511;
    int32_t idx = (int32_t)(mapped / (LOG10_LUT_X_MAX_Q20 - LOG10_LUT_X_MIN_Q20));
    if (idx >= 511) return log10_lut_q20[511];
    uint32_t frac = (uint32_t)(mapped % (LOG10_LUT_X_MAX_Q20 - LOG10_LUT_X_MIN_Q20));
    uint32_t denom = (uint32_t)(LOG10_LUT_X_MAX_Q20 - LOG10_LUT_X_MIN_Q20);
    int64_t y0 = log10_lut_q20[idx];
    int64_t y1 = log10_lut_q20[idx + 1];
    return (int32_t)(y0 + ((y1 - y0) * (int64_t)frac) / denom);
}

/* ── Sqrt: uint64_t Q40 → uint32_t Q20 (binary search) ──────── */
uint32_t sqrt_q40_to_q20(uint64_t x_q40)
{
    if (x_q40 == 0) return 0;
    /* We need sqrt(x_q40 * 2^(-40)) * 2^20 = sqrt(x_q40) * 2^(-20) * 2^20 = sqrt(x_q40) */
    /* Actually: sqrt_q40_to_q20 means x is in Q40 (×2^40), result in Q20 (×2^20) */
    /* result = sqrt(x_q40 / 2^40) * 2^20 = sqrt(x_q40) / 2^20 * 2^20 = sqrt(x_q40) */
    /* But x_q40 = actual_value * 2^40, so sqrt(actual_value) * 2^20 = sqrt(x_q40 * 2^(-40)) * 2^20 = sqrt(x_q40) */
    /* Wait — let us be precise: */
    /*   x_float = x_q40 / 2^40 */
    /*   result_float = sqrt(x_float) */
    /*   result_q20 = result_float * 2^20 */
    /*   result_q20 = sqrt(x_q40 / 2^40) * 2^20 */
    /*   result_q20 = sqrt(x_q40) / 2^20 * 2^20 = sqrt(x_q40) */
    /* So: result_q20 = sqrt(x_q40). No formatting needed. */
    /* Binary search for integer sqrt */
    uint64_t lo = 0;
    uint64_t hi = (uint64_t)1 << 32;  /* sqrt of max Q40 can be up to ~2^31 */
    if (hi > 0xFFFFFFFFULL) hi = 0xFFFFFFFFULL;
    while (lo < hi) {
        uint64_t mid = (lo + hi + 1) >> 1;
        if (mid * mid <= x_q40)
            lo = mid;
        else
            hi = mid - 1;
    }
    return (uint32_t)lo;
}
